// Unit 11. L'imparfait
// Imperfect Tense

export default {n:11,lang:"fr",srcLang:"en",track:"v2",title:"L'imparfait",sub:"Imperfect Tense",icon:"🌫️",level:"A2.3",color:"#7B5EE8",lessons:[
  {id:"fre11l1",title:"L'imparfait",icon:"🌫️",xp:15,board:true,steps:[
        {type:"intro",title:"L'imparfait: the other past tense",desc:"The imparfait describes ongoing, habitual, or background actions in the past. While passé composé tells WHAT happened, imparfait tells what WAS happening or USED to happen.",goals:["Understand when to use imparfait","Distinguish from passé composé","Form the imparfait stem"]},
        {type:"tip",title:"Imparfait vs passé composé",text:"PASSÉ COMPOSÉ: completed, specific events\nJ'ai mangé une pizza. (I ate a pizza.)\n\nIMPARFAIT: ongoing, habitual, descriptive\nJe mangeais toujours des pizzas. (I always used to eat pizzas.)\nIl faisait beau. (The weather was nice.)\n\nThink of imparfait as the 'background' tense.\nPassé composé is the 'event' tense."},
        {type:"teach",trg:"je mangeais",src:"I was eating / I used to eat",pos:"verb",gender:null,phonetic:"zhuh mahn-ZHAY",note:"Imparfait of manger.\nStem: mange- (nous form minus -ons).\nEnding: -ais (je).",example:"A: Tu mangeais souvent au restaurant avant?\nB: Oui, je mangeais au restaurant tous les jours.\nA: Et maintenant?",exampleSrc:"A: Did you used to eat at restaurants often?\nB: Yes, I used to eat at restaurants every day.\nA: And now?",funFact:"I was eating / used to eat. Imperfect. -ais for je/tu. Ongoing/habitual past."},
        {type:"tip",title:"How to form the imparfait",text:"Take the NOUS form of present tense.\nRemove -ons to get the stem.\nAdd imparfait endings:\n\nje: -ais\ntu: -ais\nil/elle/on: -ait\nnous: -ions\nvous: -iez\nils/elles: -aient\n\nExample: manger -> nous mangeons -> mange-\nje mangeais, tu mangeais, il mangeait...\n\nONLY exception: être (stem = ét-)."},
        {type:"teach",trg:"il faisait beau",src:"the weather was nice",pos:"verb",gender:null,phonetic:"eel fuh-ZAY BOH",note:"Faisait = imparfait of faire.\nStem: fais- (nous faisons -> fais-).\nIl faisait = it was doing / it was (weather).",example:"A: Il faisait beau hier?\nB: Oui, il faisait très beau.\nA: Dommage, j'ai travaillé!",exampleSrc:"A: Was the weather nice yesterday?\nB: Yes, it was very nice.\nA: Too bad, I worked!",funFact:"The weather was nice. Classic imperfect for weather/background."},
        {type:"teach",trg:"nous habitions",src:"we used to live",pos:"verb",gender:null,phonetic:"nooz ah-bee-tee-ON",note:"Habitions = imparfait of habiter.\nStem: habit- (nous habitons -> habit-).\nNous ending: -ions.",example:"A: Vous habitiez où avant?\nB: Nous habitions à Lyon.\nA: Vous aimez mieux Paris?",exampleSrc:"A: Where did you used to live?\nB: We used to live in Lyon.\nA: Do you prefer Paris?",funFact:"We lived / were living. Imperfect -ions for nous. Background-past setting."},
        {type:"mc",q:"The imparfait is used for:",opts:["Ongoing or habitual past actions","Completed events","Future plans","Commands"],ans:"Ongoing or habitual past actions",hint:"What WAS happening or what you USED to do regularly."},
        {type:"fb",opts:["ais","ait","ions","aient"],hint:"First person singular imparfait ending.",s:"Je mange{1} toujours au café. (imparfait ending for je)",a:"ais"},
        {type:"mc",q:"To form the imparfait stem, you take the ___ form and remove -ons:",opts:["Je","Nous","Tu","Ils"],ans:"Nous",hint:"The first person plural present tense form is the starting point."},
        {type:"fb",opts:["ait","ais","ions","aient"],hint:"Third person singular imparfait ending.",s:"Il fais{1} beau hier. (imparfait ending for il)",a:"ait"},
        {type:"match",pairs:[{trg:"je -ais",src:"I was..."},{trg:"tu -ais",src:"you were..."},{trg:"il -ait",src:"he was..."},{trg:"nous -ions",src:"we were..."}]},
        {type:"mc",q:"The ONLY verb with an irregular imparfait stem is:",opts:["Avoir","Aller","Être","Faire"],ans:"Être",hint:"All other verbs use the regular nous-minus-ons stem."},
        {type:"fb",opts:["ions","iez","ais","aient"],hint:"We used to live: nous + which imparfait ending?",s:"Nous habit{1} à Lyon avant.",a:"ions"},
        {type:"match",pairs:[{trg:"vous -iez",src:"you were..."},{trg:"ils -aient",src:"they were..."},{trg:"elles -aient",src:"they (f.) were..."},{trg:"on -ait",src:"one/we was/were..."}]},
        {type:"mc",q:"'Je mangeais' can mean:",opts:["Only 'I was eating'","Only 'I used to eat'","I will eat","Both 'I was eating' and 'I used to eat'"],ans:"Both 'I was eating' and 'I used to eat'",hint:"The imparfait covers ___ ongoing and habitual meanings."},
        {type:"fb",opts:["eaient","eais","eait","eions"],hint:"They used to eat: ils + which imparfait ending?",s:"Ils mang{1} au restaurant tous les vendredis.",a:"eaient"},
        {type:"mc",q:"'Il faisait beau' describes:",opts:["The background weather condition","A specific weather event","Tomorrow's weather","A weather command"],ans:"The background weather condition",hint:"Imparfait for descriptions = ___/setting information."},
        {type:"fb",opts:["ais","ait","ions","aient"],hint:"Second person singular shares its ending with je.",s:"Tu parl{1} français quand tu étais petit? (imparfait ending for tu)",a:"ais"}
  ]},
  {id:"fre11l2",title:"La formation",icon:"🔨",xp:15,board:true,steps:[
        {type:"intro",title:"Forming the imparfait",desc:"Practice forming the imparfait for different verb groups. The stem always comes from the nous present form. The only exception is être (stem: ét-).",goals:["Form imparfait for -er, -ir, -re verbs","Use the être exception (ét-)","Conjugate confidently for all persons"]},
        {type:"teach",trg:"j'étais",src:"I was",pos:"noun",gender:null,phonetic:"zhay-TAY",note:"Être has an irregular stem: ét-.\nj'étais, tu étais, il était,\nnous étions, vous étiez, ils étaient.",example:"A: Tu étais où hier soir?\nB: J'étais chez moi.\nA: Tu étais malade?",exampleSrc:"A: Where were you last night?\nB: I was at home.\nA: Were you sick?",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"tu avais",src:"you had / you used to have",pos:"verb",gender:null,phonetic:"tew ah-VAY",note:"Avoir: nous avons -> av-.\nj'avais, tu avais, il avait,\nnous avions, vous aviez, ils avaient.\nRegular stem!",example:"A: Tu avais un chien avant?\nB: Oui, j'avais un petit chien.\nA: Il s'appelait comment?",exampleSrc:"A: Did you used to have a dog?\nB: Yes, I had a little dog.\nA: What was its name?",funFact:"You had. Irregular imperfect of avoir. Stem av- + -ais."},
        {type:"teach",trg:"elle finissait",src:"she was finishing / she used to finish",pos:"verb",gender:null,phonetic:"el fee-nee-SAY",note:"Finir: nous finissons -> finiss-.\nThe -iss- extends to all forms.\nj'finissais, tu finissais, il finissait...",example:"A: Elle finissait toujours ses devoirs?\nB: Oui, elle finissait avant le dîner.\nA: Quelle bonne élève!",exampleSrc:"A: Did she always finish her homework?\nB: Yes, she used to finish before dinner.\nA: What a good student!",funFact:"She was finishing. Imperfect of finir (-ir). -issait in 3rd person."},
        {type:"teach",trg:"ils vendaient",src:"they used to sell",pos:"verb",gender:null,phonetic:"eel vahn-DAY",note:"Vendre: nous vendons -> vend-.\nils vendaient.\nRegular -re verb stem.",example:"A: Ils vendaient quoi avant?\nB: Ils vendaient des vêtements.\nA: Et maintenant?",exampleSrc:"A: What did they used to sell?\nB: They used to sell clothes.\nA: And now?",funFact:"They were selling. Imperfect of vendre (-re). -aient for 3rd plural."},
        {type:"mc",q:"Être is the only exception. Its imparfait stem is:",opts:["Ét-","Êt-","Ét","Étai-"],ans:"Ét-",hint:"Not from nous sommes (irregular). Special stem with accent."},
        {type:"fb",opts:["étais","était","suis","ai"],hint:"I was tired. Imparfait of être, first person.",s:"J'{1} fatigué hier soir.",a:"étais"},
        {type:"match",pairs:[{trg:"j'étais",src:"I was"},{trg:"tu étais",src:"you were"},{trg:"il était",src:"he was"},{trg:"nous étions",src:"we were"}]},
        {type:"mc",q:"For finir, the imparfait stem is finiss- because:",opts:["It's irregular","Nous finissons -> finiss-","It sounds better","The -iss- is always added"],ans:"Nous finissons -> finiss-",hint:"Take the ___ present form. Remove -ons. That's the stem."},
        {type:"fb",opts:["ais","ait","aient","ions"],hint:"You were how old? Tu + which imparfait ending?",s:"Tu av{1} quel âge en 2010?",a:"ais"},
        {type:"mc",q:"The imparfait endings je and tu are:",opts:["Different","Similar: -ais/-ait","Identical: -ais","Identical: -ait"],ans:"Identical: -ais",hint:"Both je and tu share the exact same ending in imparfait."},
        {type:"fb",opts:["ait","ais","ions","aient"],hint:"She used to finish. Il/elle/on ending?",s:"Elle finiss{1} toujours avant les autres.",a:"ait"},
        {type:"match",pairs:[{trg:"ils étaient",src:"they were"},{trg:"vous étiez",src:"you were (formal)"},{trg:"elles avaient",src:"they (f.) had"},{trg:"on était",src:"one/we was/were"}]},
        {type:"mc",q:"The nous and vous imparfait endings are:",opts:["-ais / -ait","-ais / -iez","-ions / -aient","-ions / -iez"],ans:"-ions / -iez",hint:"These two forms share the -i- sound in their endings."},
        {type:"fb",opts:["étions","étiez","étaient","étais"],hint:"We were students. Nous + être imparfait.",s:"Nous {1} étudiants à Paris. (to be)",a:"étions"},
        {type:"mc",q:"'Ils vendaient' and 'elles vendaient' are:",opts:["Identical forms","Different forms","Wrong grammar","Future tense"],ans:"Identical forms",hint:"Both ils and elles use the same -aient ending."},
        {type:"fb",opts:["alliez","allions","allaient","allais"],hint:"Did you used to go? Vous + stem (all-) + -iez.",s:"Vous {1} souvent au parc? (to go, imparfait)",a:"alliez"},
        {type:"mc",q:"Which verb group keeps -iss- in the imparfait stem?",opts:["-er verbs","-ir verbs (like finir)","-re verbs","All groups"],ans:"-ir verbs (like finir)",hint:"Nous finissons -> finiss-. The -iss- pattern is characteristic."}
  ]},
  {id:"fre11l3",title:"Descriptions au passé",icon:"🖼️",xp:15,board:true,steps:[
        {type:"intro",title:"Describing the past with imparfait",desc:"Imparfait is THE tense for descriptions: what things looked like, how people felt, what the weather was like. It paints the background picture.",goals:["Describe past weather","Describe past emotions and states","Set the scene for a story"]},
        {type:"teach",trg:"il faisait froid",src:"it was cold",pos:"verb",gender:null,phonetic:"eel fuh-ZAY FRWAH",note:"Weather in the past = imparfait.\nIl faisait + weather adjective.\nIl pleuvait = it was raining.",example:"A: Il faisait quel temps?\nB: Il faisait froid et il pleuvait.\nA: Pas très agréable!",exampleSrc:"A: What was the weather like?\nB: It was cold and it was raining.\nA: Not very pleasant!",funFact:"It was cold. Weather + imperfect. Faire is versatile."},
        {type:"teach",trg:"j'avais faim",src:"I was hungry",pos:"intj",gender:null,phonetic:"zhah-VAY FAN",note:"Physical states in past = imparfait.\nJ'avais faim = I was hungry.\nJ'avais soif = I was thirsty.",example:"A: Tu avais faim?\nB: Oui, j'avais très faim!\nA: Tu as mangé quoi?",exampleSrc:"A: Were you hungry?\nB: Yes, I was very hungry!\nA: What did you eat?",funFact:"I was hungry. Imperfect + faim (hunger). French uses avoir for hunger: avoir faim."},
        {type:"teach",trg:"elle était contente",src:"she was happy",pos:"verb",gender:null,phonetic:"el ay-TAY kon-TAHNT",note:"Emotions in past = imparfait.\nIl/elle était + adjective.\nDescribes how someone FELT (state, not event).",example:"A: Marie était contente?\nB: Oui, elle était très contente du cadeau.\nA: Tant mieux!",exampleSrc:"A: Was Marie happy?\nB: Yes, she was very happy with the gift.\nA: Good!",funFact:"She was happy. Être + imperfect + feminine agreement."},
        {type:"teach",trg:"il y avait",src:"there was / there were",pos:"verb",gender:null,phonetic:"eel ee ah-VAY",note:"Il y a (present) -> il y avait (imparfait).\nDescribes what existed as background.",example:"A: Il y avait beaucoup de monde?\nB: Oui, il y avait au moins cent personnes!\nA: C'était bondé!",exampleSrc:"A: Were there a lot of people?\nB: Yes, there were at least a hundred people!\nA: It was packed!",funFact:"There was / there were. Imperfect of il y a. Background existence."},
        {type:"mc",q:"Past weather uses imparfait because weather is:",opts:["A background description","An event","A completed action","A question"],ans:"A background description",hint:"Weather sets the scene. It's not an event but a condition."},
        {type:"fb",opts:["ait","ais","ions","aient"],hint:"It was nice and hot. Il + imparfait ending.",s:"Il fais{1} beau et chaud.",a:"ait"},
        {type:"match",pairs:[{trg:"il faisait froid",src:"it was cold"},{trg:"il faisait chaud",src:"it was hot"},{trg:"il pleuvait",src:"it was raining"},{trg:"il neigeait",src:"it was snowing"}]},
        {type:"mc",q:"'J'avais faim' uses imparfait because hunger is:",opts:["An event","A state/condition","A completed action","A future plan"],ans:"A state/condition",hint:"Being hungry describes how you felt, not what you did."},
        {type:"fb",opts:["avait","a","avais","avaient"],hint:"There were many people. Il y + imparfait of avoir.",s:"Il y {1} beaucoup de monde au marché.",a:"avait"},
        {type:"mc",q:"'C'était magnifique' means:",opts:["It will be magnificent","It's magnificent","It was magnificent","Be magnificent!"],ans:"It was magnificent",hint:"C'était = it was. Imparfait of être for descriptions."},
        {type:"fb",opts:["était","étais","a été","est"],hint:"She was tired. Feminine description in the past.",s:"Elle {1} fatiguée après le travail.",a:"était"},
        {type:"match",pairs:[{trg:"j'avais faim",src:"I was hungry"},{trg:"j'avais soif",src:"I was thirsty"},{trg:"j'avais peur",src:"I was afraid"},{trg:"j'avais froid",src:"I was cold"}]},
        {type:"mc",q:"Which sentence paints a background picture?",opts:["J'ai mangé une pizza","Je suis allé au cinéma","J'ai fini mon travail","Je mangeais quand il est arrivé"],ans:"Je mangeais quand il est arrivé",hint:"I WAS eating (ongoing background) when he arrived (event)."},
        {type:"fb",opts:["était","a été","est","étais"],hint:"It was a beautiful day. Background description = imparfait.",s:"C'{1} une belle journée.",a:"était"},
        {type:"mc",q:"The imparfait of 'there is/are' is built from which present-tense expression?",opts:["Il y a","Il y a eu","Il y aura","Il y est"],ans:"Il y a",hint:"The imparfait drops the present ending and adds past endings instead."},
        {type:"fb",opts:["étaient","étais","était","ont été"],hint:"The children were happy. Ils/elles + être imparfait.",s:"Les enfants {1} contents de voir leurs grands-parents.",a:"étaient"},
        {type:"mc",q:"Setting a scene: 'Il faisait beau, les oiseaux chantaient, et les enfants jouaient.' All verbs are in:",opts:["Passé composé","Imparfait","Present","Future"],ans:"Imparfait",hint:"All background descriptions painting a picture of the past."}
  ]},
  {id:"fre11l4",title:"Les habitudes",icon:"🔁",xp:15,board:true,steps:[
        {type:"intro",title:"Past habits with imparfait",desc:"The imparfait is perfect for 'used to' and 'would always'. Describe routines, habits, and repeated actions from the past.",goals:["Express past habits with imparfait","Use frequency words (toujours, souvent, etc.)","Describe childhood routines"]},
        {type:"teach",trg:"Quand j'étais petit(e)...",src:"When I was little...",pos:"verb",gender:null,phonetic:"kahn zhay-TAY puh-TEE",note:"Classic imparfait opener for childhood memories.\nPetit (masc.) / petite (fem.).\nTriggers imparfait for all following verbs.",example:"A: Quand tu étais petit, tu aimais quoi?\nB: Quand j'étais petit, j'adorais le chocolat.\nA: Et maintenant?",exampleSrc:"A: When you were little, what did you like?\nB: When I was little, I loved chocolate.\nA: And now?",funFact:"When I was small. Imperfect opener for childhood. Gender in parens."},
        {type:"teach",trg:"on allait toujours",src:"we always used to go",pos:"intj",gender:null,phonetic:"on ah-LAY too-ZHOOR",note:"On allait = we used to go.\nToujours = always.\nHabitual action = imparfait.",example:"A: Vous alliez en vacances?\nB: Oui, on allait toujours à la mer.\nA: C'était bien!",exampleSrc:"A: Did you used to go on vacation?\nB: Yes, we always used to go to the sea.\nA: That was nice!",funFact:"We always used to go. Imperfect of aller + toujours (always). Habitual past."},
        {type:"teach",trg:"souvent",src:"often",pos:"adv",gender:null,phonetic:"soo-VAHN",note:"Frequency word that triggers imparfait.\nSouvent = often, frequently.\nOther triggers: toujours, chaque jour, d'habitude.",example:"A: Tu allais souvent au cinéma?\nB: Oui, j'allais souvent au cinéma le samedi.\nA: Quel genre de films?",exampleSrc:"A: Did you often go to the cinema?\nB: Yes, I often went to the cinema on Saturdays.\nA: What kind of movies?",funFact:"French adverbs often end in -ment (like English -ly), formed from the feminine adjective."},
        {type:"teach",trg:"d'habitude",src:"usually / normally",pos:"noun",gender:null,phonetic:"dah-bee-TEWD",note:"D'habitude = usually, normally.\nStrong imparfait trigger.\nSignals a repeated routine.",example:"A: D'habitude, tu mangeais à quelle heure?\nB: D'habitude, je mangeais à midi.\nA: Et le soir?",exampleSrc:"A: Usually, what time did you eat?\nB: Usually, I ate at noon.\nA: And in the evening?",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"'Quand j'étais petit' triggers imparfait because it describes:",opts:["A habitual/ongoing past time that was recurring","A specific one-time event (in most cases)","The future with precision (in most cases)","A direct spoken command (in most cases) (in most cases)"],ans:"A habitual/ongoing past time that was recurring",hint:"Childhood = a period of ___ with repeated habits and states."},
        {type:"fb",opts:["allais","suis allé","vais","irai"],hint:"I used to go. Habitual past action.",s:"Quand j'étais petit, je {1} au parc tous les jours. (to go)",a:"allais"},
        {type:"match",pairs:[{trg:"toujours",src:"always"},{trg:"souvent",src:"often"},{trg:"d'habitude",src:"usually"},{trg:"chaque jour",src:"every day"}]},
        {type:"mc",q:"Choosing between two past tenses: which one describes a repeated past habit?",opts:["J'ai mangé hier","Je mangeais","Both together","Neither one fits"],ans:"Je mangeais",hint:"One tense marks a completed event; the other expresses routine or ongoing state."},
        {type:"fb",opts:["regardait","a regardé","regarde","regardera"],hint:"Usually, we used to watch. Habitual past = imparfait.",s:"D'habitude, on {1} la télé le soir. (to watch)",a:"regardait"},
        {type:"mc",q:"Which sentence describes a past habit?",opts:["J'ai mangé une pizza une seule fois","Je mange des pizzas régulièrement","Je mangeais des pizzas tous les jours","Je vais manger une pizza ce soir"],ans:"Je mangeais des pizzas tous les jours",hint:"'Every day' + imparfait = habitual past action."},
        {type:"fb",opts:["jouaient","ont joué","jouent","joueront"],hint:"The children used to play. Habitual action, they/elles form.",s:"Les enfants {1} dans le jardin chaque après-midi. (to play)",a:"jouaient"},
        {type:"match",pairs:[{trg:"je mangeais",src:"I used to eat"},{trg:"j'allais",src:"I used to go"},{trg:"je regardais",src:"I used to watch"},{trg:"je dormais",src:"I used to sleep"}]},
        {type:"mc",q:"'Tous les étés, nous allions à la plage' uses imparfait because:",opts:["It happened once long ago","It will happen in the future","It's happening right now, currently","It was a repeated action every summer"],ans:"It was a repeated action every summer",hint:"Tous les étés = ___ ___. ___ = habitual past."},
        {type:"fb",opts:["faisait","a fait","fait","fera"],hint:"My grandmother always used to make. Habitual action.",s:"Ma grand-mère {1} toujours des gâteaux. (to make)",a:"faisait"},
        {type:"mc",q:"Imparfait signal words include all EXCEPT:",opts:["Hier à 15h","Souvent","Toujours","D'habitude"],ans:"Hier à 15h",hint:"A specific time yesterday points to a completed event (passé composé)."},
        {type:"fb",opts:["étais","ai été","suis","serai"],hint:"When I was little. Être in the imparfait.",s:"Quand j'{1} petit, j'adorais les dinosaures.",a:"étais"},
        {type:"mc",q:"'Avant, je prenais le bus. Maintenant, je prends le métro.' The imparfait shows:",opts:["Current habit","A past habit that changed","A future plan","A command"],ans:"A past habit that changed",hint:"Avant (before) + imparfait = a ___ that no longer exists."}
  ]},
  {id:"fre11l5",title:"Être à l'imparfait",icon:"🔤",xp:15,board:true,steps:[
        {type:"intro",title:"Être in the imparfait",desc:"Être is the most important imparfait verb. It appears in descriptions (c'était), states (j'étais fatigué), and age expressions (j'avais 10 ans). Master all its forms.",goals:["Conjugate être in imparfait for all persons","Use c'était for descriptions","Describe past states and conditions"]},
        {type:"teach",trg:"c'était",src:"it was",pos:"noun",gender:null,phonetic:"say-TAY",note:"C'était = it was. THE most common imparfait.\nC'était bien = it was good.\nC'était nul = it was terrible.",example:"A: Le restaurant était bien?\nB: Oui, c'était excellent!\nA: On y retourne?",exampleSrc:"A: Was the restaurant good?\nB: Yes, it was excellent!\nA: Shall we go back?",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"j'avais dix ans",src:"I was ten years old",pos:"intj",gender:null,phonetic:"zhah-VAY deez AHN",note:"Age in the past = avoir + age + ans.\nImparfait because age is a state.\nJ'avais 20 ans quand... is very common.",example:"A: Tu avais quel âge en 2010?\nB: J'avais dix ans.\nA: Tu te souviens?",exampleSrc:"A: How old were you in 2010?\nB: I was ten.\nA: Do you remember?",funFact:"I was ten years old. Imperfect + age pattern. Avoir + X ans is the age formula."},
        {type:"teach",trg:"il/elle s'appelait",src:"his/her name was",pos:"intj",gender:null,phonetic:"eel/el sah-PLAY",note:"S'appeler in imparfait.\nIl s'appelait = his name was.\nUsed for past introductions.",example:"A: Comment s'appelait ton professeur?\nB: Il s'appelait Monsieur Dupont.\nA: Il était sévère?",exampleSrc:"A: What was your teacher's name?\nB: His name was Mr. Dupont.\nA: Was he strict?",funFact:"His/her name was. Imperfect of reflexive s'appeler. Background-past description."},
        {type:"mc",q:"'C'était bien' is used to describe:",opts:["A past experience","A future event","A current state","A command"],ans:"A past experience",hint:"C'était = it was. For describing ___ ___s."},
        {type:"fb",opts:["avais","ai eu","ai","aurai"],hint:"I was twenty. Age in the past uses avoir + imparfait.",s:"J'{1} vingt ans quand j'ai commencé l'université.",a:"avais"},
        {type:"match",pairs:[{trg:"j'étais",src:"I was"},{trg:"c'était",src:"it was"},{trg:"j'avais ... ans",src:"I was ... years old"},{trg:"il s'appelait",src:"his name was"}]},
        {type:"mc",q:"For age in the past, French uses:",opts:["Être + age","Avoir + age (imparfait)","Aller + age","Faire + age"],ans:"Avoir + age (imparfait)",hint:"J'avais dix ans, not j'étais dix ans. French 'has' years."},
        {type:"fb",opts:["était","est","a été","étais"],hint:"It was a beautiful evening. Third person imparfait.",s:"C'{1} une belle soirée.",a:"était"},
        {type:"mc",q:"'Comment s'appelait ton chien?' asks about:",opts:["The dog's age","The dog's color","The dog's name","The dog's breed"],ans:"The dog's name",hint:"S'appeler = to be called/___d. Past tense for a former pet."},
        {type:"fb",opts:["ait","ais","ions","aient"],hint:"Her name was Sophie. Il/elle + imparfait ending.",s:"Elle s'appel{1} Sophie quand elle était petite.",a:"ait"},
        {type:"match",pairs:[{trg:"c'était bien",src:"it was good"},{trg:"c'était nul",src:"it was terrible"},{trg:"c'était amusant",src:"it was fun"},{trg:"c'était difficile",src:"it was difficult"}]},
        {type:"mc",q:"Which uses imparfait correctly?",opts:["C'est magnifique","Ça sera magnifique","C'a été magnifique","C'était magnifique"],ans:"C'était magnifique",hint:"For past descriptions/evaluations, use the imparfait of être."},
        {type:"fb",opts:["étions","sommes","avons été","serons"],hint:"We were very happy to see you. Nous + être imparfait.",s:"Nous {1} très contents de vous voir.",a:"étions"},
        {type:"mc",q:"'Les rues étaient vides' means:",opts:["The streets were empty","The streets are empty","The streets will be empty","Empty the streets"],ans:"The streets were empty",hint:"Étaient = imparfait of être, ils/elles form. Past description."},
        {type:"fb",opts:["étiez","étais","êtes","avez été"],hint:"Where were you in 2015? Vous + être imparfait.",s:"Vous {1} où en 2015?",a:"étiez"},
        {type:"mc",q:"'J'avais 5 ans et je m'appelais Coco.' This describes:",opts:["Current facts","Past states and identities","Future plans","Commands"],ans:"Past states and identities",hint:"Age and name in the ___ = imparfait. ___, not events."},
        {type:"fb",opts:["étaient","sont","ont été","étais"],hint:"They were tired. Ils + être imparfait.",s:"Ils {1} fatigués après le voyage.",a:"étaient"}
  ]},
  {id:"fre11l6",title:"Imparfait + passé composé",icon:"⚡",xp:15,board:true,steps:[
        {type:"intro",title:"Using both past tenses together",desc:"In real French, imparfait and passé composé work TOGETHER. The imparfait sets the scene (background), the passé composé tells what happened (event).",goals:["Combine both tenses in one sentence","Use quand/pendant que patterns","Recognize background vs event"]},
        {type:"tip",title:"The movie analogy",text:"Think of it like a movie scene:\n\nIMPARFAIT = the camera showing the setting\nIl faisait beau. Les gens marchaient.\n(It was nice. People were walking.)\n\nPASSÉ COMPOSÉ = the action that happens\nSoudain, il a commencé à pleuvoir!\n(Suddenly, it started to rain!)\n\nBackground + Event = French storytelling."},
        {type:"teach",trg:"Je dormais quand le téléphone a sonné.",src:"I was sleeping when the phone rang.",pos:"verb",gender:null,phonetic:"zhuh dor-MAY kahn luh tay-lay-FON ah soh-NAY",note:"Classic pattern:\nIMPARFAIT (ongoing) + QUAND + PASSÉ COMPOSÉ (event).\nI WAS doing X when Y HAPPENED.",example:"A: Tu as répondu au téléphone?\nB: Non, je dormais quand il a sonné.\nA: Tu dormais déjà à dix heures?",exampleSrc:"A: Did you answer the phone?\nB: No, I was sleeping when it rang.\nA: You were already sleeping at ten?",funFact:"I was sleeping when the phone rang. Imperfect (background) + passé composé (event)."},
        {type:"teach",trg:"Pendant qu'il pleuvait, j'ai lu un livre.",src:"While it was raining, I read a book.",pos:"intj",gender:null,phonetic:"pahn-DAHN keel pluh-VAY zhay lew uhn LEE-vruh",note:"Pendant que + imparfait = while something was ongoing.\nMain clause = passé composé (the event).",example:"A: Tu as fait quoi pendant la pluie?\nB: Pendant qu'il pleuvait, j'ai lu un livre.\nA: C'était un bon livre?",exampleSrc:"A: What did you do during the rain?\nB: While it was raining, I read a book.\nA: Was it a good book?",funFact:"While it was raining, I read a book. Pendant que + imperfect + passé composé. Classic narrative pair."},
        {type:"mc",q:"'Je mangeais quand il est arrivé.' The imparfait describes:",opts:["The ongoing eating in the background","The sudden arrival","A future meal together","A daily repeated habit"],ans:"The ongoing eating in the background",hint:"I WAS ___ (scene) when he arrived (event)."},
        {type:"fb",opts:["pleuvait","a plu","pleut","pleuvra"],hint:"It was raining when we went out. Ongoing weather = imparfait.",s:"Il {1} quand nous sommes sortis. (to rain, imparfait)",a:"pleuvait"},
        {type:"match",pairs:[
          {trg:"Je dormais (background)",src:"I was sleeping"},
          {trg:"le téléphone a sonné (event)",src:"the phone rang"},
          {trg:"Il pleuvait (background)",src:"it was raining"},
          {trg:"j'ai pris un taxi (event)",src:"I took a taxi"}
        ]},
        {type:"mc",q:"She worked (background). He cooked (event). Who performed the passé composé action?",opts:["Elle","Il","Both","Neither"],ans:"Il",hint:"The passé composé marks the event. Look at which subject performs that tense."},
        {type:"fb",opts:["regardais","ai regardé","regarde","regarderai"],hint:"I was watching TV when you called. Ongoing action.",s:"Je {1} la télé quand tu as appelé. (to watch, imparfait)",a:"regardais"},
        {type:"mc",q:"Which sentence combines both tenses correctly?",opts:["Je mangeais et je dormais tout le temps","J'ai mangé et puis j'ai dormi longtemps","Je mangeais quand il est arrivé","Je mange quand il arrive à la maison"],ans:"Je mangeais quand il est arrivé",hint:"Background (imparfait) + event (passé composé) in one sentence."},
        {type:"fb",opts:["jouaient","ont joué","jouent","joueront"],hint:"The children were playing when mom came home. Ongoing action.",s:"Les enfants {1} quand la mère est rentrée. (to play, imparfait)",a:"jouaient"},
        {type:"match",pairs:[{trg:"quand",src:"when (+ event)"},{trg:"pendant que",src:"while (+ background)"},{trg:"soudain",src:"suddenly (+ event)"},{trg:"il faisait beau",src:"it was nice (background)"}]},
        {type:"mc",q:"'Soudain' (suddenly) usually introduces:",opts:["Imparfait","Future","Present","Passé composé"],ans:"Passé composé",hint:"Suddenly = a specific, sudden event. Events use the completed tense."},
        {type:"fb",opts:["a commencé","commençait","commence","commencera"],hint:"It was nice. Suddenly, it started to rain. Sudden event.",s:"Il faisait beau. Soudain, il {1} à pleuvoir. (to start, PC)",a:"a commencé"},
        {type:"mc",q:"Three past sentences: a day, weather, and a decision. Which one is the specific event?",opts:["J'ai décidé de sortir","Il faisait beau","C'était dimanche","All three"],ans:"J'ai décidé de sortir",hint:"The passé composé marks what happened. The other two paint the scene."},
        {type:"fb",opts:["marchions","avons marché","marchons","marcherons"],hint:"We were walking when we saw Pierre. Ongoing background action.",s:"Nous {1} dans la rue quand nous avons vu Pierre. (to walk, imparfait)",a:"marchions"},
        {type:"mc",q:"Summary: imparfait = ___, passé composé = ___.",opts:["Event, background","Background, event","Both events","Both backgrounds"],ans:"Background, event",hint:"Imparfait paints the scene, passé composé tells what happened."},
        {type:"fb",opts:["chantait","a chanté","chante","chantera"],hint:"She was singing when I arrived. Ongoing background action.",s:"Elle {1} quand je suis arrivé. (to sing, imparfait)",a:"chantait"}
  ]},
  {id:"fre11l7",title:"Quand j'étais jeune",icon:"👶",xp:15,board:true,steps:[
        {type:"intro",title:"When I was young: childhood memories",desc:"Practice telling extended stories about the past using imparfait for habits and descriptions, and passé composé for specific events. Share childhood memories.",goals:["Tell a childhood story","Mix descriptions, habits, and events","Use extended narrative in French"]},
        {type:"teach",trg:"Quand j'étais jeune...",src:"When I was young...",pos:"intj",gender:null,phonetic:"kahn zhay-TAY ZHUHN",note:"Classic story opener.\nEverything after uses imparfait\n(for ongoing states) or passé composé (for events).",example:"A: Quand j'étais jeune, j'habitais à la campagne.\nB: C'était comment?\nA: C'était calme et on jouait dehors tous les jours.",exampleSrc:"A: When I was young, I lived in the countryside.\nB: What was it like?\nA: It was quiet and we played outside every day.",funFact:"When I was young... Imperfect opener. Same as u11 example; reinforces pattern."},
        {type:"teach",trg:"un jour",src:"one day",pos:"noun",gender:"m",phonetic:"uhn ZHOOR",note:"'Un jour' introduces a specific event\nwithin a habitual narrative.\nSwitches from imparfait to passé composé.",example:"A: Un jour, j'ai trouvé un chat dans le jardin.\nB: Tu l'as gardé?\nA: Oui, il est resté avec nous dix ans!",exampleSrc:"A: One day, I found a cat in the garden.\nB: Did you keep it?\nA: Yes, it stayed with us ten years!",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"mc",q:"'Quand j'étais jeune, j'aimais...' continues with:",opts:["Imparfait","Passé composé","Present","Future"],ans:"Imparfait",hint:"After 'quand j'étais jeune', habitual verbs stay in the same tense."},
        {type:"fb",opts:["étais","ai été","suis","serai"],hint:"When I was young. Être in the imparfait.",s:"Quand j'{1} jeune, j'adorais la natation.",a:"étais"},
        {type:"match",pairs:[
          {trg:"j'habitais à la campagne",src:"I used to live in the country"},
          {trg:"on jouait dehors",src:"we used to play outside"},
          {trg:"c'était calme",src:"it was quiet"},
          {trg:"il faisait toujours beau",src:"it was always nice"}
        ]},
        {type:"mc",q:"'Un jour, j'ai trouvé...' switches to passé composé because:",opts:["It describes a habit","It's a specific, one-time event","It describes weather","It describes a feeling"],ans:"It's a specific, one-time event",hint:"Un jour = one day. A ___ moment breaks the habitual pattern."},
        {type:"fb",opts:["jouait","a joué","joue","jouera"],hint:"We used to play soccer every Saturday. Habitual action.",s:"On {1} au foot tous les samedis. (to play, imparfait)",a:"jouait"},
        {type:"mc",q:"In a childhood story, descriptions and habits use:",opts:["Passé composé","Present","Imparfait","Conditional"],ans:"Imparfait",hint:"The 'background' tense for ongoing states and repeated actions."},
        {type:"fb",opts:["ai","avais","étais","suis"],hint:"One day, I met my best friend. Specific event = passé composé.",s:"Un jour, j'{1} rencontré mon meilleur ami. (to meet, PC)",a:"ai"},
        {type:"match",pairs:[{trg:"un jour (event trigger)",src:"one day"},{trg:"soudain (event trigger)",src:"suddenly"},{trg:"toujours (habit trigger)",src:"always"},{trg:"chaque été (habit trigger)",src:"every summer"}]},
        {type:"mc",q:"'Ma grand-mère habitait à Nice. Elle faisait toujours des crêpes.' Both verbs are imparfait because:",opts:["They are events","They are future","They happened once","They describe habits and states"],ans:"They describe habits and states",hint:"Where she lived (state) and what she always made (habit)."},
        {type:"fb",opts:["racontait","a raconté","raconte","racontera"],hint:"My father always used to tell stories. Habitual action.",s:"Mon père {1} toujours des histoires avant de dormir. (to tell, imparfait)",a:"racontait"},
        {type:"mc",q:"Pick the correct mix: 'Il pleuvait et soudain le soleil ___.'",opts:["A brillé (passé composé)","Brillait (imparfait)","Brille (present)","Brillera (future)"],ans:"A brillé (passé composé)",hint:"Soudain = suddenly. Triggers a specific event in the completed tense."},
        {type:"fb",opts:["allions","sommes allés","allons","irons"],hint:"We used to go to the sea every summer. Habitual.",s:"Quand j'étais petit, nous {1} à la mer chaque été. (to go, imparfait)",a:"allions"},
        {type:"mc",q:"Complete the story logically: 'Il faisait beau. Les enfants jouaient. Soudain, ___.'",opts:["Il faisait froid (imparfait)","Un chien a aboyé (passé composé)","Les oiseaux chantaient (imparfait)","C'était calme (imparfait)"],ans:"Un chien a aboyé (passé composé)",hint:"After soudain, you need a specific event to break the scene."},
        {type:"fb",opts:["était","est","a été","sera"],hint:"It was the most beautiful day. Past evaluation = imparfait.",s:"C'{1} le plus beau jour de ma vie!",a:"était"},
        {type:"mc",q:"The imparfait is sometimes called the 'background' or 'movie camera' tense because:",opts:["It records events","It plays music","It shows the ongoing scene before action happens","It is used in movies"],ans:"It shows the ongoing scene before action happens",hint:"Like a camera panning across a ___ ___ something ___."}
  ]},
  {id:"fre11l8",title:"Révision",icon:"🔄",xp:20,board:true,steps:[
        {type:"intro",title:"Unit 11 Review",desc:"Review the imparfait: formation, descriptions, habits, être exception, and combined use with passé composé. You now have both French past tenses.",goals:["Review imparfait formation","Test habit vs event distinction","Combine both past tenses"]},
        {type:"mc",q:"The imparfait stem comes from:",opts:["The nous present form minus -ons","The je present form directly","The simple infinitive stem","The ils conjugated form"],ans:"The nous present form minus -ons",hint:"Take ___ ___, remove the ending. That's your stem."},
        {type:"fb",opts:["étais","ai été","suis","serai"],hint:"I was happy. State in the past = être imparfait.",s:"J'{1} content de te voir hier.",a:"étais"},
        {type:"match",pairs:[{trg:"-ais (je/tu)",src:"1st/2nd singular"},{trg:"-ait (il/elle/on)",src:"3rd singular"},{trg:"-ions (nous)",src:"1st plural"},{trg:"-aient (ils/elles)",src:"3rd plural"}]},
        {type:"mc",q:"'Il faisait beau et les oiseaux chantaient' is:",opts:["Two sequential events","A description/scene","Two direct commands","A question for clarity"],ans:"A description/scene",hint:"Weather + ongoing action = background/___ painting."},
        {type:"fb",opts:["allais","suis allé","vais","irai"],hint:"I used to go. Habitual past action = imparfait.",s:"Quand j'étais petit, je {1} au parc tous les jours. (to go)",a:"allais"},
        {type:"mc",q:"Which signals passé composé (not imparfait)?",opts:["Toujours","D'habitude","Soudain","Chaque jour"],ans:"Soudain",hint:"Suddenly = a specific event breaking the background."},
        {type:"fb",opts:["ait","ais","ions","aient"],hint:"It was raining when I went out. Il + imparfait ending.",s:"Il pleuv{1} quand je suis sorti.",a:"ait"},
        {type:"match",pairs:[{trg:"c'était bien",src:"it was good"},{trg:"j'avais faim",src:"I was hungry"},{trg:"il y avait",src:"there was/were"},{trg:"il faisait froid",src:"it was cold"}]},
        {type:"mc",q:"A sentence has two verbs: one imparfait, one passé composé. Which is the passé composé?",opts:["Mangeais","Neither","Both","Est arrivé"],ans:"Est arrivé",hint:"One is the ongoing background; the other is the specific interrupting event."},
        {type:"fb",opts:["allions","sommes allés","allons","irons"],hint:"We often used to go. Habitual action, nous form.",s:"Nous {1} souvent au cinéma le samedi. (to go, imparfait)",a:"allions"},
        {type:"mc",q:"The only verb with an irregular imparfait stem is:",opts:["Être","Faire","Aller","Avoir"],ans:"Être",hint:"Stem = ét-. All other verbs use nous-minus-ons regularly."},
        {type:"fb",opts:["jouaient","ont joué","jouent","joueront"],hint:"The children were playing. Ongoing background action.",s:"Les enfants {1} dehors quand il a commencé à pleuvoir. (to play)",a:"jouaient"},
        {type:"match",pairs:[{trg:"imparfait: habit",src:"je mangeais toujours..."},{trg:"imparfait: description",src:"il faisait beau"},{trg:"PC: event",src:"j'ai mangé une pizza"},{trg:"PC: soudain",src:"soudain, il a plu"}]},
        {type:"mc",q:"Which correctly combines both tenses?",opts:["J'ai mangé et j'ai dormi","Il pleuvait quand j'ai quitté la maison","Je mangeais et je dormais","Il a plu quand j'ai quitté"],ans:"Il pleuvait quand j'ai quitté la maison",hint:"Background (imparfait) + event (passé composé) = correct combo."},
        {type:"fb",opts:["était","est","a été","étais"],hint:"It was a Sunday. Background description = imparfait.",s:"C'{1} un dimanche. Il faisait beau.",a:"était"},
        {type:"mc",q:"You now know both French past tenses. What's the key distinction?",opts:["Formal address vs informal speech","Written language vs spoken dialect","Background/habit vs completed event","Old French vs modern French"],ans:"Background/habit vs completed event",hint:"Imparfait = ongoing/___ual. Passé composé = ___/specific."},
        {type:"fb",opts:["adorais","ai adoré","adore","adorerai"],hint:"When I was young, I used to love. Childhood habit.",s:"Quand j'étais jeune, j'{1} le chocolat. (to love)",a:"adorais"}
  ]},
  {id:"frv2_u11l_shopping_travel_money",title:"Achats et voyages",icon:"🛍️",xp:20,board:true,steps:[
        {type:"intro",title:"Shopping, travel, and money",desc:"Learn essential A2 vocabulary for shopping, trips, and handling money. These words appear constantly in everyday situations: markets, stores, and travel.",goals:["Name types of shops and markets","Talk about spending and prices","Use key verbs for choosing and forgetting"]},
        {type:"teach",trg:"le magasin",src:"the shop / the store",pos:"noun",gender:"m",phonetic:"luh ma-ga-ZAN",note:"Masculine noun. Au magasin = at the shop.\nFaire les magasins = to go shopping (browse).",example:"A: Tu vas où?\nB: Je vais au magasin. J'ai besoin de pain.\nA: Quel magasin?\nB: Le petit magasin au coin de la rue.",exampleSrc:"A: Where are you going?\nB: I am going to the shop. I need bread.\nA: Which shop?\nB: The small shop on the street corner.",funFact:"From Old French 'magazin', ultimately from Arabic 'makhazin' (storehouses). French has many Arabic-origin words from medieval trade routes."},
        {type:"teach",trg:"le marché",src:"the market",pos:"noun",gender:"m",phonetic:"luh mar-SHAY",note:"Masculine noun. Au marché = at the market.\nLe marché en plein air = open-air market.",example:"A: Il y a un marché le samedi matin?\nB: Oui, le marché est place de la Mairie.\nA: On y va ensemble?\nB: Oui, bonne idée!",exampleSrc:"A: Is there a market Saturday morning?\nB: Yes, the market is on the town hall square.\nA: Shall we go together?\nB: Yes, good idea!",funFact:"French outdoor markets (marchés) date back to the Middle Ages. Most towns still hold weekly markets where locals buy fresh produce directly from farmers."},
        {type:"teach",trg:"le voyage",src:"the trip / the journey",pos:"noun",gender:"m",phonetic:"luh vwa-YAZH",note:"Masculine noun. Faire un voyage = to take a trip.\nBon voyage! = Have a good trip!",example:"A: Tu pars bientôt?\nB: Oui, j'ai un voyage en juillet.\nA: C'est un long voyage?\nB: Non, c'est un court voyage.",exampleSrc:"A: Are you leaving soon?\nB: Yes, I have a trip in July.\nA: Is it a long trip?\nB: No, it is a short trip.",funFact:"'Bon voyage!' is used in English too, borrowed directly from French. The word 'voyage' comes from Latin 'viaticum' (travel provisions)."},
        {type:"teach",trg:"dépenser",src:"to spend (money)",pos:"verb",gender:null,phonetic:"day-pahn-SAY",note:"Regular -er verb. dépenser de l'argent = to spend money.\nDo not confuse with payer (to pay).",example:"A: Tu dépenses beaucoup au marché?\nB: Non, je dépense environ dix euros.\nA: C'est raisonnable!\nB: Oui, je fais attention.",exampleSrc:"A: Do you spend a lot at the market?\nB: No, I spend about ten euros.\nA: That is reasonable!\nB: Yes, I am careful.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"cher / chère",src:"expensive / dear",pos:"adj",gender:null,phonetic:"SHEHR",note:"Masculine: cher. Feminine: chère.\nC'est cher = it is expensive.\nMon cher ami = my dear friend (different meaning).",example:"A: Ce magasin est cher?\nB: Oui, c'est très cher.\nA: Le marché est moins cher.\nB: Oui, j'achète au marché.",exampleSrc:"A: Is this shop expensive?\nB: Yes, it is very expensive.\nA: The market is less expensive.\nB: Yes, I buy at the market.",funFact:"'Cher' has two meanings: expensive and dear (beloved). Context makes it clear. In a letter, 'Cher Paul' means 'Dear Paul', not 'Expensive Paul'."},
        {type:"teach",trg:"bon marché",src:"cheap / inexpensive",pos:"adj",gender:null,phonetic:"bon mar-SHAY",note:"Invariable: bon marché never changes form.\nC'est bon marché = it is cheap.\nOpposite: cher.",example:"A: Les fruits sont bon marché au marché?\nB: Oui, c'est vraiment bon marché.\nA: Je vais y aller demain.\nB: Bonne idée!",exampleSrc:"A: Is fruit cheap at the market?\nB: Yes, it is really cheap.\nA: I will go there tomorrow.\nB: Good idea!",funFact:"Unlike most French adjectives, 'bon marché' is invariable. It never adds -e or -s, no matter the noun's gender or number. This is rare in French."},
        {type:"tip",title:"Cher vs. bon marché",text:"French has two simple ways to talk about price:\n\nCHER / CHÈRE: expensive\nC'est cher. (It is expensive.)\nCette veste est chère. (This jacket is expensive.)\n\nBON MARCHÉ: cheap (invariable adjective)\nC'est bon marché. (It is cheap.)\nCes fruits sont bon marché. (This fruit is cheap.)\n\nBon marché never changes form: no feminine, no plural endings."},
        {type:"teach",trg:"la monnaie",src:"change / coins / currency",pos:"noun",gender:"f",phonetic:"la mo-NAY",note:"Feminine noun. Rendre la monnaie = to give change.\nLa monnaie = (small) change, coins, or currency in general.",example:"A: Vous avez la monnaie?\nB: Non, je n'ai pas de monnaie.\nA: Ce n'est pas grave.\nB: J'ai un billet de vingt euros.",exampleSrc:"A: Do you have change?\nB: No, I do not have change.\nA: That is all right.\nB: I have a twenty-euro note.",funFact:"French 'monnaie' gave English the word 'money' via Old Norman French. The modern English 'money' and French 'monnaie' are cousins from the same Latin root 'moneta'."},
        {type:"teach",trg:"choisir",src:"to choose / to select",pos:"verb",gender:null,phonetic:"shwah-ZEER",note:"Regular -ir verb (finir group). je choisis, tu choisis, il choisit.\nChoisir entre = to choose between.",example:"A: Tu veux quelle couleur?\nB: Je n'arrive pas à choisir!\nA: Tu aimes le bleu ou le rouge?\nB: Je choisis le bleu.",exampleSrc:"A: Which colour do you want?\nB: I cannot manage to choose!\nA: Do you like blue or red?\nB: I choose blue.",funFact:"'Choisir' belongs to the -ir verb group modelled on 'finir'. These verbs add -iss- in plural forms: nous choisissons, vous choisissez, ils choisissent."},
        {type:"teach",trg:"oublier",src:"to forget",pos:"verb",gender:null,phonetic:"oo-blee-YAY",note:"Regular -er verb. J'oublie, tu oublies, il oublie.\nN'oublie pas! = Don't forget!",example:"A: Tu as le billet?\nB: Oh non, j'ai oublié le billet!\nA: Il faut rentrer!\nB: Oui, vite!",exampleSrc:"A: Do you have the ticket?\nB: Oh no, I forgot the ticket!\nA: We have to go back!\nB: Yes, quickly!",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"mc",q:"'Le magasin' means:",opts:["the shop","the trip","the change","the market"],ans:"the shop",hint:"A general word for any retail store, not an outdoor food market."},
        {type:"fb",opts:["dépense","choisit","oublie","voyage"],hint:"She spends too much at the shop. Which verb means 'to spend'?",s:"Elle {1} trop au magasin.",a:"dépense"},
        {type:"mc",q:"Which adjective means 'cheap' and never changes form?",opts:["chère","bon marché","bon","cher"],ans:"bon marché",hint:"This two-word adjective is invariable: no feminine or plural endings."},
        {type:"fb",opts:["voyage","marché","magasin","monnaie"],hint:"An outdoor weekly market where you buy fresh produce.",s:"On achète des légumes frais au {1} du samedi.",a:"marché"},
        {type:"match",pairs:[{trg:"le magasin",src:"the shop"},{trg:"le marché",src:"the market"},{trg:"le voyage",src:"the trip"},{trg:"la monnaie",src:"the change / coins"}]},
        {type:"mc",q:"'J'ai oublié mon billet.' This means:",opts:["I found my ticket","I bought my ticket","I forgot my ticket","I chose my ticket"],ans:"I forgot my ticket",hint:"Oublier = to forget. J'ai oublié = I … (passé composé)."},
        {type:"fb",opts:["cher","chère","bon marché","riche"],hint:"This jacket is expensive (feminine noun: la veste).",s:"Cette veste est {1}.",a:"chère"},
        {type:"mc",q:"The verb 'choisir' follows which pattern?",opts:["Irregular -re","Completely irregular","Regular -er (like parler)","Regular -ir (like finir)"],ans:"Regular -ir (like finir)",hint:"It adds -iss- in plural forms: nous choisissons."},
        {type:"fb",opts:["oublier","choisir","dépenser","voyager"],hint:"I cannot decide between the red and the blue one. Which verb?",s:"Je n'arrive pas à {1} entre le rouge et le bleu.",a:"choisir"},
        {type:"match",pairs:[{trg:"dépenser",src:"to spend money"},{trg:"oublier",src:"to forget"},{trg:"choisir",src:"to choose"},{trg:"cher",src:"expensive"}]},
        {type:"mc",q:"'La monnaie' in French means:",opts:["change/coins/currency","the wallet","the menu","the money (general)"],ans:"change/coins/currency",hint:"It can mean small …, …, or a country's …. 'Rendre la monnaie' = to give …."},
        {type:"fb",opts:["bon marché","cher","chère","bonne"],hint:"At the market everything is inexpensive. The two-word invariable adjective for cheap.",s:"Au marché, tout est {1}.",a:"bon marché"},
        {type:"mc",q:"'Bon voyage!' is said when someone:",opts:["Arrives home","Is about to travel","Forgets something","Pays at the cashier"],ans:"Is about to travel",hint:"This French expression is used in English too. Le voyage = the trip."},
        {type:"fb",opts:["dépenses","choisis","oublies","voyages"],hint:"Don't spend too much at the shop! Tu form of dépenser.",s:"Ne {1} pas trop au magasin!",a:"dépenses"}
  ]},
  {id:"fre11l8b",title:"Les Animaux",icon:"🐶",xp:15,board:true,steps:[
        {type:"intro",title:"Les Animaux",desc:"Learn the names of common animals in French.",goals:["Learn 15 animal names with le/la/l'","Use articles correctly with animal nouns","Talk about pets and wildlife"]},
        {type:"teach",trg:"l'animal",src:"the animal (m)",pos:"noun",gender:"m",phonetic:"la-nee-MAL",note:"l'animal: masculine noun.\nPlural irregular: les animaux.",example:"A: Tu aimes les animaux ?\nB: Oui, j'adore les animaux !\nA: Tu as un animal de compagnie ?\nB: Oui, j'ai un chat.",exampleSrc:"A: Do you like animals?\nB: Yes, I love animals!\nA: Do you have a pet?\nB: Yes, I have a cat.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"le chien",src:"the dog",pos:"noun",gender:"m",phonetic:"luh shee-EN",note:"le chien: masculine noun.\nFemale dog: la chienne.",example:"A: Tu as un chien ?\nB: Oui, j'ai un petit chien.\nA: Comment il s'appelle ?\nB: Il s'appelle Max.",exampleSrc:"A: Do you have a dog?\nB: Yes, I have a small dog.\nA: What is his name?\nB: His name is Max.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le chat",src:"the cat",pos:"noun",gender:"m",phonetic:"luh SHA",note:"le chat: masculine noun.\nFemale cat: la chatte.",example:"A: Tu aimes les chats ?\nB: Oui, les chats sont adorables.\nA: Tu as un chat ?\nB: Non, mais je veux un chat roux.",exampleSrc:"A: Do you like cats?\nB: Yes, cats are adorable.\nA: Do you have a cat?\nB: No, but I want an orange cat.",funFact:"Cognate with English 'cat'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"l'oiseau",src:"the bird (m)",pos:"noun",gender:"m",phonetic:"lwa-ZO",note:"l'oiseau: masculine noun.\nPlural irregular: les oiseaux.",example:"A: Regarde, un oiseau !\nB: Oh, il est bleu et jaune.\nA: C'est un perroquet.\nB: Il est magnifique.",exampleSrc:"A: Look, a bird!\nB: Oh, it is blue and yellow.\nA: It is a parrot.\nB: It is magnificent.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"le poisson",src:"the fish",pos:"noun",gender:"m",phonetic:"luh pwa-SON",note:"le poisson: masculine noun.\nDo not confuse with le poison (poison).",example:"A: Tu as des poissons ?\nB: Oui, j'ai trois poissons rouges.\nA: Ils sont dans un aquarium ?\nB: Oui, un grand aquarium.",exampleSrc:"A: Do you have fish?\nB: Yes, I have three goldfish.\nA: Are they in a fish tank?\nB: Yes, a big fish tank.",funFact:"Fish. From Latin 'piscis.' Double 's' reflects the double consonant. Related to Spanish 'pescado,' Italian 'pesce.' Same Pisces root."},
        {type:"teach",trg:"le lapin",src:"the rabbit",pos:"noun",gender:"m",phonetic:"luh la-PAN",note:"le lapin: masculine noun.\nFemale: la lapine.",example:"A: Tu veux voir mon lapin ?\nB: Oh oui ! Il est mignon.\nA: Il s'appelle Flocon.\nB: Ses oreilles sont grandes !",exampleSrc:"A: Do you want to see my rabbit?\nB: Oh yes! He is cute.\nA: His name is Flocon.\nB: His ears are big!",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le cheval",src:"the horse",pos:"noun",gender:"m",phonetic:"luh shuh-VAL",note:"le cheval: masculine noun.\nPlural irregular: les chevaux.",example:"A: Tu fais du cheval ?\nB: Oui, tous les samedis.\nA: C'est difficile ?\nB: Non, c'est amusant.",exampleSrc:"A: Do you go horseback riding?\nB: Yes, every Saturday.\nA: Is it difficult?\nB: No, it is fun.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"la vache",src:"the cow",pos:"noun",gender:"f",phonetic:"la VASH",note:"la vache: feminine noun.\nMale: le taureau (bull).",example:"A: Il y a des vaches dans le champ.\nB: Oui, elles mangent de l'herbe.\nA: Elles donnent du lait.\nB: Le lait frais est delicieux.",exampleSrc:"A: There are cows in the field.\nB: Yes, they eat grass.\nA: They give milk.\nB: Fresh milk is delicious.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"le cochon",src:"the pig",pos:"noun",gender:"m",phonetic:"luh ko-SHON",note:"le cochon: masculine noun.\nFemale: la truie.",example:"A: Les cochons sont roses ?\nB: Oui, souvent roses ou bruns.\nA: Ils sont intelligents ?\nB: Oui, tres intelligents !",exampleSrc:"A: Are pigs pink?\nB: Yes, often pink or brown.\nA: Are they intelligent?\nB: Yes, very intelligent!",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"la poule",src:"the chicken/hen",pos:"noun",gender:"f",phonetic:"la POOL",note:"la poule: feminine noun (hen).\nle poulet: chicken (meat).\nle coq: rooster.",example:"A: Il y a des poules dans le jardin.\nB: Oui, elles donnent des oeufs.\nA: Combien d'oeufs par jour ?\nB: Trois ou quatre oeufs.",exampleSrc:"A: There are chickens in the garden.\nB: Yes, they lay eggs.\nA: How many eggs per day?\nB: Three or four eggs.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"le mouton",src:"the sheep",pos:"noun",gender:"m",phonetic:"luh moo-TON",note:"le mouton: masculine noun.\nFemale: la brebis.",example:"A: Regarde les moutons dans le champ.\nB: Il y en a beaucoup.\nA: Leur laine est tres douce.\nB: Oui, on fait des pulls avec.",exampleSrc:"A: Look at the sheep in the field.\nB: There are many of them.\nA: Their wool is very soft.\nB: Yes, sweaters are made from it.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le lion",src:"the lion",pos:"noun",gender:"m",phonetic:"luh lee-ON",note:"le lion: masculine noun.\nFemale: la lionne.",example:"A: Tu as vu le lion au zoo ?\nB: Oui, il est enorme !\nA: Il rugit fort.\nB: C'est impressionnant.",exampleSrc:"A: Did you see the lion at the zoo?\nB: Yes, it is enormous!\nA: It roars loudly.\nB: It is impressive.",funFact:"Cognate with English 'lion'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"l'ours",src:"the bear (m)",pos:"noun",gender:"m",phonetic:"LOORS",note:"l'ours: masculine noun.\nFemale: l'ourse.",example:"A: Il y a des ours dans cette foret ?\nB: Oui, des ours bruns.\nA: Ils sont dangereux ?\nB: Oui, il faut faire attention.",exampleSrc:"A: Are there bears in this forest?\nB: Yes, brown bears.\nA: Are they dangerous?\nB: Yes, you must be careful.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"le zoo",src:"the zoo",pos:"noun",gender:"m",phonetic:"luh ZO",note:"le zoo: masculine noun.\nSame pronunciation as English.",example:"A: On va au zoo dimanche ?\nB: Oui, bonne idee !\nA: Je veux voir les singes.\nB: Moi, je veux voir les pingouins.",exampleSrc:"A: Shall we go to the zoo on Sunday?\nB: Yes, good idea!\nA: I want to see the monkeys.\nB: I want to see the penguins.",funFact:"Same word in both languages. English borrowed thousands of words from French."},
        {type:"teach",trg:"l'animal de compagnie",src:"the pet",pos:"noun",gender:"m",phonetic:"la-nee-MAL duh kom-pa-NYEE",note:"Literally: companion animal.\nPlural: des animaux de compagnie.",example:"A: Tu as un animal de compagnie ?\nB: Oui, j'ai un chien et un chat.\nA: Deux animaux ! C'est bien.\nB: Ils s'entendent tres bien.",exampleSrc:"A: Do you have a pet?\nB: Yes, I have a dog and a cat.\nA: Two animals! That's nice.\nB: They get along very well.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"Which word means 'the dog' in French?",opts:["le chien","le chat","le lapin","le cochon"],ans:"le chien",hint:"Think of the word that sounds like 'shee-EN'."},
        {type:"mc",q:"What is the correct article for 'oiseau'?",opts:["la","l'","le","les"],ans:"l'",hint:"This noun starts with a vowel, so the article contracts."},
        {type:"fb",opts:["chat","chien","oiseau","poisson"],hint:"This pet is known for loving milk and purring.",s:"Mon {1} s'appelle Felix, il adore le lait.",a:["chat"]},
        {type:"fb",opts:["vaches","poules","moutons","cochons"],hint:"These farm animals are the primary source of dairy.",s:"Les {1} donnent du lait frais chaque jour.",a:["vaches"]},
        {type:"match",pairs:[{trg:"le chien",src:"the dog"},{trg:"le chat",src:"the cat"},{trg:"le lapin",src:"the rabbit"},{trg:"la poule",src:"the chicken"},{trg:"le cheval",src:"the horse"}]},
        {type:"mc",q:"Comment dit-on 'bear' en francais ?",opts:["le lion","le loup","l'ours","le tigre"],ans:"l'ours",hint:"This masculine noun starts with a vowel and lives in forests."},
        {type:"fb",opts:["zoo","parc","marche","cinema"],hint:"A place specifically designed to house and display wild animals.",s:"On va au {1} pour voir les animaux sauvages.",a:["zoo"]}
  ,{type:"match",pairs:[{trg:"le poisson",src:"the fish"},{trg:"le mouton",src:"the sheep"}]}]}
]};
